128	  const scenario = input as Scenario;
129	  const policies: Policy[] = [];
130	  let quoteCount = 0;
131	  const results = scenario.steps.map((step) => {
132	    if (step.op === "quote") {
133	      const result = quote(step, {
134	        customer: scenario.customer,
135	        isFollowup: quoteCount > 0,
136	      });
137	      quoteCount++;
138	      policies.push({
139	        items: step.items,
140	        remainingCap: policyInsuranceSum(step.items) * CAP_MULTIPLIER,
141	      });
142	      return result;
143	    }
144	    return claim(step, policies);
145	  });
146	  return { results };
147	};
