const openPolicy = (items: Item[]): Policy => ({
  items,
  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
});

const processQuote = (
  step: QuoteStep,
  customer: Customer,
  policies: Policy[],
) => {
  const result = quote(step, { customer, isFollowup: policies.length > 0 });
  policies.push(openPolicy(step.items));
  return result;
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const policies: Policy[] = [];
  const results = scenario.steps.map((step) =>
    step.op === "quote"
      ? processQuote(step, scenario.customer, policies)
      : claim(step, policies),
  );
  return { results };
};
